inline double calcLikelihoodSum(__global unsigned char * I, __global int * ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    for (int x = 0; x < numOnes; x++) {
        double diff1 = (double)(I[ind[index * numOnes + x]] - 100);
        double diff2 = (double)(I[ind[index * numOnes + x]] - 228);
